gold_sparql:
SELECT ?decade ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
  {
    SELECT ?paper ?decade
           (MAX(?is_flag) AS ?has_is)
           (MAX(?ml_flag) AS ?has_ml)
    WHERE {
      ?paper orkgp:P31 ?contribution ;
             orkgp:P29 ?year .

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue ;
                    orkgp:P15124 ?data_analysis .

      ?venue rdfs:label ?venue_name .
      ?data_analysis rdfs:label ?da_label .

      BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
      BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

      OPTIONAL {
        ?data_analysis orkgp:P56043 ?inferential_statistics .
        BIND(1 AS ?is_flag)
      }

      OPTIONAL {
        ?data_analysis orkgp:P57016 ?machine_learning .
        BIND(1 AS ?ml_flag)
      }

      FILTER(?da_label != "no analysis"^^xsd:string)
      FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    }
    GROUP BY ?paper ?decade
  }

  BIND(
    IF(?has_is = 1 && ?has_ml = 1, "both"^^xsd:string,
      IF(?has_is = 1 && (!BOUND(?has_ml) || ?has_ml != 1), "inferential-statistics only"^^xsd:string,
        IF((!BOUND(?has_is) || ?has_is != 1) && ?has_ml = 1, "machine-learning only"^^xsd:string,
          "neither"^^xsd:string
        )
      )
    ) AS ?reporting_case
  )
}
GROUP BY ?decade ?reporting_case
ORDER BY ?decade ?reporting_case

